import React, { useState, useEffect, useRef } from 'react';

function PlayButton() {
  const [isPlaying, setIsPlaying] = useState(false);
  const [metadata, setMetadata] = useState('CURRENTLY OFF-AIR');
  const audioRef = useRef(null);

  const handlePlayToggle = () => {
    if (!isPlaying) {
      audioRef.current.play();
    } else {
      audioRef.current.pause();
    }
    setIsPlaying(!isPlaying);
  };

  useEffect(() => {
    if (isPlaying) {
      audioRef.current.addEventListener('loadedmetadata', () => {
        const audio = audioRef.current;
        if (audio) {
          const currentMetadata = audio.mozCurrentMetadata || {};
          const title = currentMetadata.title || 'Unknown Title';
          const artist = currentMetadata.artist || 'Unknown Artist';
          const newMetadata = `${title} - ${artist}`;
          setMetadata(newMetadata);
        }
      });
    }
  }, [isPlaying]);

  return (
    <div>
      <button className="play-button" onClick={handlePlayToggle}>
        {isPlaying ? '❚❚' : '▶'}
      </button>
      <audio ref={audioRef} src="http://172.232.62.146:8000/radio.mp3" />
      <Marquee metadata={metadata} />
    </div>
  );
}

export default PlayButton;
